import com.fasterxml.jackson.core.type.TypeReference;
import com.fasterxml.jackson.databind.ObjectMapper;
import org.thymeleaf.TemplateEngine;
import org.thymeleaf.context.Context;
import org.thymeleaf.templatemode.TemplateMode;
import org.thymeleaf.templateresolver.FileTemplateResolver;

import java.io.BufferedReader;
import java.io.File;
import java.io.InputStreamReader;
import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.nio.file.Paths;
import java.util.Map;
import java.util.stream.Collectors;

public class CliTemplateProcessor {

    public static void main(String[] args) {
        String templatePath = null;
        String dataPath     = null;
        boolean dataStream  = false;

        // 1. Parse Named Arguments
        for (int i = 0; i < args.length; i++) {
            switch (args[i]) {
                case "--template-path":
                    if (i + 1 < args.length) templatePath = args[++i];
                    break;
                case "--data-path":
                    if (i + 1 < args.length) dataPath = args[++i];
                    break;
                case "--data-stream":
                    dataStream = true;
                    break;
                default:
                    System.err.println("Unknown argument: " + args[i]);
                    printUsage();
                    System.exit(1);
            }
        }

        // 2. Validate Argument Logic
        if (templatePath == null) {
            System.err.println("Error: --template-path is required.");
            printUsage();
            System.exit(1);
        }
        if (dataPath == null && !dataStream) {
            System.err.println("Error: You must provide either --data-path or --data-stream.");
            printUsage();
            System.exit(1);
        }
        if (dataPath != null && dataStream) {
            System.err.println("Error: Cannot use --data-path and --data-stream at the same time.");
            printUsage();
            System.exit(1);
        }

        try {
            // 3. Retrieve JSON Data String
            String jsonContent;
            if (dataStream) {
                try (BufferedReader reader = new BufferedReader(
                        new InputStreamReader(System.in, StandardCharsets.UTF_8))) {
                    jsonContent = reader.lines().collect(Collectors.joining("\n"));
                }
            } else {
                jsonContent = Files.readString(Paths.get(dataPath), StandardCharsets.UTF_8);
            }

            // 4. Parse JSON into Variables Map
            ObjectMapper objectMapper = new ObjectMapper();
            Map<String, Object> variables = objectMapper.readValue(
                    jsonContent,
                    new TypeReference<Map<String, Object>>() {}
            );

            // 5. Detect Template Mode based on file extension
            TemplateMode mode = templatePath.toLowerCase().endsWith(".html")
                    || templatePath.toLowerCase().endsWith(".htm")
                    ? TemplateMode.HTML
                    : TemplateMode.TEXT;

            // 6. Configure File Resolver & Engine
            FileTemplateResolver resolver = new FileTemplateResolver();
            resolver.setTemplateMode(mode);
            resolver.setCharacterEncoding("UTF-8");
            resolver.setCacheable(false);

            TemplateEngine templateEngine = new TemplateEngine();
            templateEngine.setTemplateResolver(resolver);

            // 7. Inject Variables and Execute
            Context context = new Context();
            context.setVariables(variables);

            String output = templateEngine.process(templatePath, context);
            System.out.print(output);

        } catch (Exception e) {
            System.err.println("Error processing execution: " + e.getMessage());
            System.exit(1);
        }
    }

    private static void printUsage() {
        System.err.println("\nUsage Options:");
        System.err.println("  --template-path <path>  Absolute path to the template file (.html or .txt)");
        System.err.println("  --data-path <path>      Absolute path to a local JSON data file");
        System.err.println("  --data-stream           Flag to read the JSON content from standard input stream");
    }
}

import * as vscode from 'vscode'
import * as fs from 'fs'
import * as path from 'path'
import * as cp from 'child_process'
import * as os from 'os'

export function activate(context: vscode.ExtensionContext): void {
  const command = vscode.commands.registerCommand(
    'thymeleaf-preview.openPreview',
    () => {
      const editor = vscode.window.activeTextEditor
      if (!editor) {
        vscode.window.showErrorMessage('No active HTML file found.')
        return
      }

      const htmlFilePath = editor.document.fileName

      if (!htmlFilePath.endsWith('.html')) {
        vscode.window.showErrorMessage('Active file is not an HTML file.')
        return
      }

      const basePath = htmlFilePath.replace(/\.html$/, '')
      const jsonFilePath = `${basePath}.json`
      const propertiesFilePath = `${basePath}.properties`

      // --- Open WebView panel ---
      const panel = vscode.window.createWebviewPanel(
        'thymeleafPreview',
        `Preview: ${path.basename(htmlFilePath)}`,
        vscode.ViewColumn.Beside,
        {
          enableScripts: false,
          localResourceRoots: []
        }
      )

      const jarPath = context.asAbsolutePath(path.join('bin', 'thymeleaf-cli.jar'))

      const renderPreview = (): void => {
        // --- Load JSON data ---
        let data: Record<string, unknown> = {}
        if (fs.existsSync(jsonFilePath)) {
          try {
            const raw = fs.readFileSync(jsonFilePath, 'utf-8')
            data = JSON.parse(raw)
          } catch {
            vscode.window.showWarningMessage(
              `Could not parse JSON file: ${jsonFilePath}. Using empty data.`
            )
          }
        }

        // --- Try Java CLI first, fall back to built-in JS processor ---
        if (fs.existsSync(jarPath) && fs.existsSync(jsonFilePath)) {
          renderViaJavaCli(panel, htmlFilePath, jsonFilePath, jarPath)
        } else {
          renderViaJsProcessor(panel, htmlFilePath, jsonFilePath, propertiesFilePath, data)
        }
      }

      // Initial render
      renderPreview()

      // --- VSCode FileSystemWatcher for external file changes ---
      const fsWatcher = vscode.workspace.createFileSystemWatcher(
        new vscode.RelativePattern(
          vscode.Uri.file(path.dirname(htmlFilePath)),
          `${path.basename(basePath)}.{html,json,properties}`
        ),
        false, // onCreate
        false, // onChange
        true   // ignore delete
      )

      fsWatcher.onDidChange((_uri: vscode.Uri): void => {
        renderPreview()
      })

      fsWatcher.onDidCreate((_uri: vscode.Uri): void => {
        renderPreview()
      })

      // Watch unsaved changes in the editor for the HTML file
      const onDidChangeDoc = vscode.workspace.onDidChangeTextDocument(
        (e: vscode.TextDocumentChangeEvent) => {
          if (e.document.fileName === htmlFilePath) {
            renderPreview()
          }
        }
      )

      // Cleanup on panel close
      panel.onDidDispose(() => {
        fsWatcher.dispose()
        onDidChangeDoc.dispose()
      })
    }
  )

  context.subscriptions.push(command)
}

export function deactivate(): void {}

// ---------------------------------------------------------------------------
// Render via Java CLI — uses the real Thymeleaf engine
// ---------------------------------------------------------------------------
function renderViaJavaCli(
  panel: vscode.WebviewPanel,
  htmlFilePath: string,
  jsonFilePath: string,
  jarPath: string
): void {
  const args = [
    '-jar', jarPath,
    '--template-path', htmlFilePath,
    '--data-path', jsonFilePath
  ]

  cp.execFile('java', args, { encoding: 'utf-8', maxBuffer: 10 * 1024 * 1024 }, (
    err: cp.ExecFileException | null,
    stdout: string,
    stderr: string
  ): void => {
    if (err) {
      vscode.window.showErrorMessage(`Thymeleaf CLI error: ${stderr || err.message}`)
      panel.webview.html = wrapWithToolbar(
        `<pre style="color:red;padding:1em;">${escapeHtml(stderr || err.message)}</pre>`,
        path.basename(htmlFilePath),
        'java'
      )
      return
    }

    panel.webview.html = wrapWithToolbar(stdout, path.basename(htmlFilePath), 'java')
  })
}

// ---------------------------------------------------------------------------
// Render via built-in JS processor — fallback when JAR is not available
// ---------------------------------------------------------------------------
function renderViaJsProcessor(
  panel: vscode.WebviewPanel,
  htmlFilePath: string,
  jsonFilePath: string,
  propertiesFilePath: string,
  data: Record<string, unknown>
): void {
  const i18n = loadProperties(propertiesFilePath)

  const openDoc = vscode.workspace.textDocuments.find(
    (d) => d.fileName === htmlFilePath
  )
  const rawHtml = openDoc
    ? openDoc.getText()
    : fs.existsSync(htmlFilePath)
      ? fs.readFileSync(htmlFilePath, 'utf-8')
      : ''

  const processedHtml = processThymeleaf(rawHtml, data, i18n)
  panel.webview.html = wrapWithToolbar(processedHtml, path.basename(htmlFilePath), 'js')
}

// ---------------------------------------------------------------------------
// Properties loader
// ---------------------------------------------------------------------------
function loadProperties(filePath: string): Record<string, string> {
  const result: Record<string, string> = {}
  if (!fs.existsSync(filePath)) {
    return result
  }

  const lines = fs.readFileSync(filePath, 'utf-8').split('\n')
  for (const line of lines) {
    const trimmed = line.trim()
    if (!trimmed || trimmed.startsWith('#')) {
      continue
    }
    const eqIndex = trimmed.indexOf('=')
    if (eqIndex === -1) {
      continue
    }
    const key = trimmed.substring(0, eqIndex).trim()
    const value = trimmed.substring(eqIndex + 1).trim()
    result[key] = value
  }

  return result
}

// ---------------------------------------------------------------------------
// Core Thymeleaf processor (JS fallback)
// ---------------------------------------------------------------------------
function processThymeleaf(
  html: string,
  data: Record<string, unknown>,
  i18n: Record<string, string>
): string {
  // Step 1: strip xmlns:th declaration (cosmetic)
  html = html.replace(/\s*xmlns:th="[^"]*"/g, '')

  // Step 2: process th:each loops
  html = processEachLoops(html, data, i18n)

  // Step 3: resolve th:text attributes
  html = html.replace(
    /(<[^>]+)\s+th:text="([^"]*)"([^>]*>)([^<]*)/g,
    (_match: string, openTagStart: string, thExpr: string, openTagEnd: string, _originalContent: string) => {
      const resolved = resolveExpression(thExpr, data, i18n)
      return `${openTagStart}${openTagEnd}${escapeHtml(resolved)}`
    }
  )

  // Step 4: resolve th:classappend attributes
  html = processClassAppend(html, data, i18n)

  // Step 5: resolve inline ${...} expressions in text nodes and attributes
  html = html.replace(/\$\{([^}]+)\}/g, (_match: string, varName: string) => {
    return escapeHtml(String(resolveVar(varName.trim(), data, i18n)))
  })

  // Step 6: resolve remaining #{...} i18n keys in text
  html = html.replace(/#\{([^}]+)\}/g, (_match: string, key: string) => {
    return escapeHtml(i18n[key.trim()] ?? key.trim())
  })

  return html
}

// ---------------------------------------------------------------------------
// th:each loop processor — supports optional iter/status variable
// e.g. th:each="task : ${tasks}" or th:each="task, iter : ${tasks}"
// ---------------------------------------------------------------------------
function processEachLoops(
  html: string,
  data: Record<string, unknown>,
  i18n: Record<string, string>
): string {
  const eachTagPattern = /<([a-zA-Z][a-zA-Z0-9]*)((?:[^>](?!th:each))*?)\s+th:each="([^"]+)"((?:[^>])*?)>([\s\S]*?)<\/\1>/g

  return html.replace(
    eachTagPattern,
    (
      _match: string,
      tagName: string,
      attrsBefore: string,
      eachExpr: string,
      attrsAfter: string,
      innerContent: string
    ): string => {
      const eachMatch = eachExpr.trim().match(/^(\w+)(?:\s*,\s*(\w+))?\s*:\s*\$\{([^}]+)\}$/)
      if (!eachMatch) {
        return _match
      }

      const iterVar = eachMatch[1]
      const statusVar = eachMatch[2] ?? null
      const listPath = eachMatch[3].trim()
      const listValue = resolveVar(listPath, data, i18n)

      if (!Array.isArray(listValue)) {
        return `<${tagName}${attrsBefore}${attrsAfter}>${innerContent}</${tagName}>`
      }

      return listValue
        .map((item: unknown, index: number): string => {
          const iterStatus: Record<string, unknown> = {
            index,
            count: index + 1,
            size: listValue.length,
            current: item,
            even: index % 2 === 0,
            odd: index % 2 !== 0,
            first: index === 0,
            last: index === listValue.length - 1
          }

          const scopedData: Record<string, unknown> = {
            ...data,
            [iterVar]: item,
            ...(statusVar ? { [statusVar]: iterStatus } : {})
          }

          const processedInner = processThymeleafScoped(innerContent, scopedData, i18n)
          return `<${tagName}${attrsBefore}${attrsAfter}>${processedInner}</${tagName}>`
        })
        .join('\n')
    }
  )
}

// ---------------------------------------------------------------------------
// Scoped Thymeleaf processor — used inside th:each iterations
// ---------------------------------------------------------------------------
function processThymeleafScoped(
  html: string,
  data: Record<string, unknown>,
  i18n: Record<string, string>
): string {
  // Resolve th:text
  html = html.replace(
    /(<[^>]+)\s+th:text="([^"]*)"([^>]*>)([^<]*)/g,
    (_match: string, openTagStart: string, thExpr: string, openTagEnd: string, _originalContent: string): string => {
      const resolved = resolveExpression(thExpr, data, i18n)
      return `${openTagStart}${openTagEnd}${escapeHtml(resolved)}`
    }
  )

  // Resolve th:classappend
  html = processClassAppend(html, data, i18n)

  // Resolve inline ${...}
  html = html.replace(/\$\{([^}]+)\}/g, (_match: string, varName: string): string => {
    return escapeHtml(String(resolveVar(varName.trim(), data, i18n)))
  })

  // Resolve #{...} i18n
  html = html.replace(/#\{([^}]+)\}/g, (_match: string, key: string): string => {
    return escapeHtml(i18n[key.trim()] ?? key.trim())
  })

  return html
}

// ---------------------------------------------------------------------------
// th:classappend processor
// ---------------------------------------------------------------------------
function processClassAppend(
  html: string,
  data: Record<string, unknown>,
  i18n: Record<string, string>
): string {
  return html.replace(
    /(<[a-zA-Z][a-zA-Z0-9]*(?:[^>]*?))(\s+class="([^"]*)")?((?:[^>]*?)\s+th:classappend="([^"]*)")((?:[^>]*?)>)/g,
    (
      _match: string,
      tagStart: string,
      existingClassAttr: string,
      existingClass: string,
      _thClassAppendAttr: string,
      appendExpr: string,
      tagEnd: string
    ): string => {
      const appended = resolveExpression(appendExpr, data, i18n)
      const base = existingClass ? existingClass.trim() : ''
      const newClass = base ? `${base} ${appended}` : appended
      if (existingClassAttr) {
        return `${tagStart} class="${newClass}"${tagEnd}`
      }
      return `${tagStart} class="${newClass}"${tagEnd}`
    }
  )
}

// ---------------------------------------------------------------------------
// Resolve a #messages.msg(...) call
// ---------------------------------------------------------------------------
function resolveMessagesMsg(
  argsExpr: string,
  data: Record<string, unknown>,
  i18n: Record<string, string>
): string {
  const key = resolveMessagesMsgKey(argsExpr.trim(), data)
  return i18n[key] ?? key
}

function resolveMessagesMsgKey(
  expr: string,
  data: Record<string, unknown>
): string {
  const parts = splitConcatExpression(expr)
  return parts
    .map((part: string): string => {
      part = part.trim()

      if (part.startsWith("'") && part.endsWith("'")) {
        return part.slice(1, -1)
      }

      const vMatch = part.match(/^\$\{([^}]+)\}$/)
      if (vMatch) {
        return String(resolveVar(vMatch[1].trim(), data, {}))
      }

      if (part.length > 0) {
        return String(resolveVar(part, data, {}))
      }

      return part
    })
    .join('')
}

// ---------------------------------------------------------------------------
// Expression resolver
// ---------------------------------------------------------------------------
function resolveExpression(
  expr: string,
  data: Record<string, unknown>,
  i18n: Record<string, string>
): string {
  expr = expr.trim()

  // #{key} — i18n
  const i18nMatch = expr.match(/^#\{([^}]+)\}$/)
  if (i18nMatch) {
    const key = i18nMatch[1]
    return i18n[key] ?? key
  }

  // ${#messages.msg(...)} — utility message lookup
  const msgMatch = expr.match(/^\$\{#messages\.msg\(([^)]+)\)\}$/)
  if (msgMatch) {
    return resolveMessagesMsg(msgMatch[1], data, i18n)
  }

  // ${var} — single variable
  const varMatch = expr.match(/^\$\{([^}]+)\}$/)
  if (varMatch) {
    return String(resolveVar(varMatch[1].trim(), data, i18n))
  }

  // |literal template| — Thymeleaf literal substitution syntax
  if (expr.startsWith('|') && expr.endsWith('|')) {
    const inner = expr.slice(1, -1)
    return inner.replace(/\$\{([^}]+)\}/g, (_m: string, v: string): string =>
      String(resolveVar(v.trim(), data, i18n))
    )
  }

  // Concatenation: 'string' + ${var} + #{key} + ...
  const parts = splitConcatExpression(expr)
  return parts
    .map((part: string): string => {
      part = part.trim()

      if (part.startsWith("'") && part.endsWith("'")) {
        const inner = part.slice(1, -1)
        return inner.replace(/\$\{([^}]+)\}/g, (_m: string, v: string): string =>
          String(resolveVar(v.trim(), data, i18n))
        )
      }

      const vMatch = part.match(/^\$\{([^}]+)\}$/)
      if (vMatch) {
        return String(resolveVar(vMatch[1].trim(), data, i18n))
      }

      const iMatch = part.match(/^#\{([^}]+)\}$/)
      if (iMatch) {
        return i18n[iMatch[1]] ?? iMatch[1]
      }

      return part
    })
    .join('')
}

// ---------------------------------------------------------------------------
// Split a Thymeleaf concatenation expression on `+`
// ---------------------------------------------------------------------------
function splitConcatExpression(expr: string): string[] {
  const parts: string[] = []
  let current = ''
  let i = 0

  while (i < expr.length) {
    const ch = expr[i]

    if (ch === "'") {
      current += ch
      i++
      while (i < expr.length && expr[i] !== "'") {
        current += expr[i]
        i++
      }
      if (i < expr.length) {
        current += expr[i]
        i++
      }
    } else if (ch === '$' && expr[i + 1] === '{') {
      current += ch
      i++
      while (i < expr.length && expr[i] !== '}') {
        current += expr[i]
        i++
      }
      if (i < expr.length) {
        current += expr[i]
        i++
      }
    } else if (ch === '+') {
      parts.push(current)
      current = ''
      i++
    } else {
      current += ch
      i++
    }
  }

  if (current.trim()) {
    parts.push(current)
  }

  return parts
}

// ---------------------------------------------------------------------------
// Variable resolver — supports dot notation and common method calls
// ---------------------------------------------------------------------------
function resolveVar(
  varPath: string,
  data: Record<string, unknown>,
  i18n: Record<string, string>
): unknown {
  const msgMatch = varPath.match(/^#messages\.msg\(([^)]+)\)$/)
  if (msgMatch) {
    return resolveMessagesMsg(msgMatch[1], data, i18n)
  }

  const methodMatch = varPath.match(/^(.+)\.(\w+)\(\)$/)
  if (methodMatch) {
    const objectPath = methodMatch[1]
    const methodName = methodMatch[2]
    const target = resolveVar(objectPath, data, i18n)

    if (Array.isArray(target)) {
      if (methodName === 'size' || methodName === 'length') {
        return target.length
      }
      if (methodName === 'isEmpty') {
        return target.length === 0
      }
    }

    if (typeof target === 'string') {
      if (methodName === 'length') {
        return target.length
      }
      if (methodName === 'isEmpty') {
        return target.length === 0
      }
      if (methodName === 'toUpperCase') {
        return target.toUpperCase()
      }
      if (methodName === 'toLowerCase') {
        return target.toLowerCase()
      }
      if (methodName === 'trim') {
        return target.trim()
      }
    }

    return `{{${varPath}}}`
  }

  const keys = varPath.split('.')
  let current: unknown = data
  for (const key of keys) {
    if (current === null || current === undefined || typeof current !== 'object') {
      return `{{${varPath}}}`
    }
    current = (current as Record<string, unknown>)[key]
  }
  return current ?? `{{${varPath}}}`
}

// ---------------------------------------------------------------------------
// HTML escape
// ---------------------------------------------------------------------------
function escapeHtml(text: string): string {
  return text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
}

// ---------------------------------------------------------------------------
// Wrap the processed HTML with a small dev toolbar
// ---------------------------------------------------------------------------
function wrapWithToolbar(
  html: string,
  filename: string,
  engine: 'java' | 'js'
): string {
  const engineLabel = engine === 'java'
    ? `<span style="background:#a6e3a1;color:#1e1e2e;border-radius:4px;padding:1px 6px;font-weight:bold;margin-left:6px;">☕ Java</span>`
    : `<span style="background:#f9e2af;color:#1e1e2e;border-radius:4px;padding:1px 6px;font-weight:bold;margin-left:6px;">🟨 JS Fallback</span>`

  const toolbar = `
  <div style="
    position: fixed;
    top: 0; left: 0; right: 0;
    background: #1e1e2e;
    color: #cdd6f4;
    font-family: monospace;
    font-size: 12px;
    padding: 4px 12px;
    z-index: 9999;
    display: flex;
    align-items: center;
    gap: 10px;
    border-bottom: 2px solid #89b4fa;
  ">
    <span style="color:#89b4fa;font-weight:bold;">🌿 Thymeleaf Preview</span>
    <span style="color:#a6adc8;">${filename}</span>
    ${engineLabel}
    <span style="
      margin-left: auto;
      background:#f38ba8;
      color:#1e1e2e;
      border-radius:4px;
      padding:1px 6px;
      font-weight:bold;
    ">DEV</span>
  </div>
  <div style="height:28px;"></div>`

  if (html.includes('<body>')) {
    return html.replace('<body>', `<body>${toolbar}`)
  }
  if (html.includes('<body')) {
    return html.replace(/(<body[^>]*>)/, `$1${toolbar}`)
  }
  return toolbar + html
}

